async (params, browser) => {
  // Open Spotify track page
  await browser.open(`${params.track_url}`)

  // Wait for play button to appear
  await browser.waitForSelector('[data-testid="play-button"], button[aria-label="Play"], [data-testid="action-bar-row"] button', 15000)

  // Let track page fully load
  await browser.wait(2000)

  // Click play button
  await browser.click('[data-testid="play-button"], button[aria-label="Play"]')

  // Wait for playback to start
  await browser.wait(1500)

  // Confirm playback started
  const play_result = await browser.evaluate(`const titleEl = document.querySelector('[data-testid="entityTitle"] h1, [data-testid="entityTitle"], h1'); const artistEl = document.querySelector('[data-testid="creator-link"], a[href^="/artist"]'); const nowPlaying = document.querySelector('[data-testid="now-playing-widget"], [data-testid="CoverSlotExpanded__container"]'); return { success: true, track_name: titleEl ? titleEl.textContent.trim() : '', artist: artistEl ? artistEl.textContent.trim() : '', is_playing: !!nowPlaying, url: window.location.href }`)

  return play_result
}
